Here are the public test cases for feature1_preflight_success:
{
  "description": "Preflight requests that match the configured cross-origin policy return an immediate HTTP response with the allowed origin, allowed methods, allowed request headers, and Origin in Vary.",
  "cases": [
    {
      "input": {
        "interaction": "cors_exchange",
        "exchange": "request",
        "policy": {
          "allowed_origins": "*",
          "allowed_headers": [
            "foo",
            "bar"
          ],
          "allowed_methods": [
            "POST",
            "PUT"
          ]
        },
        "request": {
          "path": "/foo",
          "method": "OPTIONS",
          "headers": {
            "Origin": "http://example.com",
            "Access-Control-Request-Method": "POST",
            "Access-Control-Request-Headers": "Foo, BAR"
          }
        }
      },
      "expected_output": "phase=request\nurl=/foo\nmethod=OPTIONS\nresponse_created=yes\nstatus=200\nheader:Access-Control-Allow-Origin=http://example.com\nheader:Access-Control-Allow-Methods=POST, PUT\nheader:Access-Control-Allow-Headers=foo, bar\nheader:Access-Control-Allow-Credentials=\nheader:Access-Control-Expose-Headers=\nheader:Access-Control-Max-Age=\nvary=Origin\nbody=\n"
    },
    {
      "input": {
        "interaction": "cors_exchange",
        "exchange": "request",
        "policy": {
          "allowed_origins": "*",
          "allowed_methods": [
            "LINK",
            "PUT"
          ]
        },
        "request": {
          "path": "/foo",
          "method": "OPTIONS",
          "headers": {
            "Origin": "http://example.com",
            "Access-Control-Request-Method": "Link"
          }
        }
      },
      "expected_output": "phase=request\nurl=/foo\nmethod=OPTIONS\nresponse_created=yes\nstatus=200\nheader:Access-Control-Allow-Origin=http://example.com\nheader:Access-Control-Allow-Methods=LINK, PUT, Link\nheader:Access-Control-Allow-Headers=\nheader:Access-Control-Allow-Credentials=\nheader:Access-Control-Expose-Headers=\nheader:Access-Control-Max-Age=\nvary=Origin\nbody=\n"
    }
  ]
}

Here are the public test cases for feature2_actual_response_headers:
{
  "description": "Actual cross-origin requests that pass the policy do not receive a request-phase response, then the final HTTP response receives only actual-response CORS headers, not preflight-only headers.",
  "cases": [
    {
      "input": {
        "interaction": "cors_exchange",
        "exchange": "response",
        "policy": {
          "allowed_origins": "*",
          "allowed_headers": [
            "foo",
            "bar"
          ],
          "allowed_methods": [
            "POST",
            "PUT"
          ]
        },
        "request": {
          "path": "/foo",
          "method": "POST",
          "headers": {
            "Origin": "http://example.com",
            "Foo": "huh",
            "BAR": "lala"
          }
        }
      },
      "expected_output": "phase=response\nurl=/foo\nmethod=POST\nresponse_created=yes\nstatus=200\nheader:Access-Control-Allow-Origin=http://example.com\nheader:Access-Control-Allow-Methods=\nheader:Access-Control-Allow-Headers=\nheader:Access-Control-Allow-Credentials=\nheader:Access-Control-Expose-Headers=\nheader:Access-Control-Max-Age=\nvary=\nbody=\n"
    }
  ]
}

Here are the public test cases for feature3_forced_origin_override:
{
  "description": "When an override allow-origin value is configured, the emitted Access-Control-Allow-Origin response header uses that override value for matching preflight requests, non-matching preflight requests, accepted actual requests, and requests without an Origin header.",
  "cases": [
    {
      "input": {
        "interaction": "cors_exchange",
        "exchange": "response",
        "policy": {
          "allowed_origins": "*",
          "allowed_methods": [
            "GET"
          ],
          "override_allow_origin": "*"
        },
        "request": {
          "path": "/foo",
          "method": "OPTIONS",
          "headers": {
            "Origin": "http://example.com",
            "Access-Control-Request-Method": "GET"
          }
        }
      },
      "expected_output": "phase=response\nurl=/foo\nmethod=OPTIONS\nresponse_created=yes\nstatus=200\nheader:Access-Control-Allow-Origin=*\nheader:Access-Control-Allow-Methods=GET\nheader:Access-Control-Allow-Headers=\nheader:Access-Control-Allow-Credentials=\nheader:Access-Control-Expose-Headers=\nheader:Access-Control-Max-Age=\nvary=Origin\nbody=\n"
    },
    {
      "input": {
        "interaction": "cors_exchange",
        "exchange": "response",
        "policy": {
          "allowed_origins": [
            "http://example.com"
          ],
          "allowed_methods": [
            "GET"
          ],
          "override_allow_origin": "http://example.com http://huh-lala.foobar"
        },
        "request": {
          "path": "/foo",
          "method": "GET",
          "headers": {
            "Origin": "http://example.com"
          }
        }
      },
      "expected_output": "phase=response\nurl=/foo\nmethod=GET\nresponse_created=yes\nstatus=200\nheader:Access-Control-Allow-Origin=http://example.com http://huh-lala.foobar\nheader:Access-Control-Allow-Methods=\nheader:Access-Control-Allow-Headers=\nheader:Access-Control-Allow-Credentials=\nheader:Access-Control-Expose-Headers=\nheader:Access-Control-Max-Age=\nvary=\nbody=\n"
    }
  ]
}

